func TestCLIMetrics_ConcurrentUpdates(t *testing.T) {
	registry := metric.NewMetricsRegistry()
	metrics := getMetrics(registry)

	// Simulate concurrent CLI operations
	done := make(chan struct{})

	// Messages published
	go func() {
		for i := 0; i < 100; i++ {
			metrics.recordMessagePublished()
			time.Sleep(time.Microsecond)
		}
		done <- struct{}{}
	}()

	// Signals sent
	go func() {
		for i := 0; i < 50; i++ {
			metrics.recordSignalSent("cancel")
			time.Sleep(time.Microsecond)
		}
		done <- struct{}{}
	}()

	// Responses received
	go func() {
		for i := 0; i < 75; i++ {
			metrics.recordResponseReceived("progress")
			time.Sleep(time.Microsecond)
		}
		done <- struct{}{}
	}()

	// Wait for all goroutines
	<-done
	<-done
	<-done

	// Verify all updates were recorded (no race conditions)
	messages := getSimpleCounterValue(t, metrics.messagesPublished)
	signals := getCounterValue(t, metrics.signalsSent, "cancel")
	responses := getCounterValue(t, metrics.responsesReceived, "progress")

	assert.GreaterOrEqual(t, messages, float64(100), "Should have at least 100 messages")
	assert.GreaterOrEqual(t, signals, float64(50), "Should have at least 50 signals")
	assert.GreaterOrEqual(t, responses, float64(75), "Should have at least 75 responses")
}

