// getCounterValue extracts the current value from a CounterVec with a label
func getCounterValue(t *testing.T, vec *prometheus.CounterVec, label string) float64 {
	t.Helper()

	counter, err := vec.GetMetricWithLabelValues(label)
	require.NoError(t, err, "Failed to get counter with label %s", label)

	var metric dto.Metric
	err = counter.Write(&metric)
	require.NoError(t, err, "Failed to write metric")

	return metric.Counter.GetValue()
}

// getSimpleCounterValue extracts the current value from a simple Counter
func getSimpleCounterValue(t *testing.T, counter prometheus.Counter) float64 {
	t.Helper()

	var metric dto.Metric
	err := counter.Write(&metric)
	require.NoError(t, err, "Failed to write metric")

	return metric.Counter.GetValue()
}
